+        impl Future for MaybeReady {
+            type Output = i32;
+            fn poll(mut self: Pin<&mut Self>, _cx: &mut Context<'_>) -> Poll<i32> {
+                self.0.take().map_or(Poll::Pending, Poll::Ready)
+            }
+        }
