+    #[test]
+    fn test_select_all_single_future() {
+        let futures = vec![std::future::ready(7)];
+        let mut sel = SelectAll::new(futures);
+
+        let result = poll_once(&mut sel);
+        assert!(matches!(result, Poll::Ready((7, 0))));
+    }
