+    #[must_use]
+    pub fn equivalent_exact(&self, other: &Self) -> bool {
+        if self.canonical.depth() != other.canonical.depth() {
+            return false;
+        }
+        for (la, lb) in self
+            .canonical
+            .layers
+            .iter()
+            .zip(other.canonical.layers.iter())
+        {
